import { createClient } from "https://esm.sh/@supabase/supabase-js@2.45.4";
import PptxGenJS from "https://esm.sh/pptxgenjs@3.12.0";
import {
  pxToInches as px,
  pxToPoints as pt,
  SLIDE_H_IN,
  SLIDE_W_IN,
  TEMPLATE_H_PX,
  TEMPLATE_W_PX,
} from "./layout.ts";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

const LAYOUT = {
  headerBand: { x: 0, y: 0, w: TEMPLATE_W_PX, h: 118 },
  chartZone: { x: 24, y: 132, w: 1392, h: 760 },
  categoryTag: { x: 40, y: 934, h: 86 },
  headlineZone: { x: 40, y: 1038, w: 1360, h: 314 },
  summaryBadge: { x: 40, y: 1368, w: 196, h: 70 },
  summaryTextZone: { x: 40, y: 1452, w: 1360, h: 206 },
  footerBand: { x: 0, y: TEMPLATE_H_PX - 122, w: TEMPLATE_W_PX, h: 122 },
} as const;

function slug(value: string) {
  return (value || "report")
    .toLowerCase()
    .replace(/[^a-z0-9가-힣]+/g, "-")
    .replace(/^-|-$/g, "")
    .slice(0, 40) || "report";
}

function toStorageKeySegment(value: string, fallback: string) {
  const normalized = (value || "")
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "")
    .slice(0, 40);

  return normalized || fallback;
}

function normalizeCategoryLookupKey(raw: string) {
  return raw.trim().toUpperCase().replace(/\s+/g, " ");
}

const HEADER_TITLE_TEXT = {
  REAL_ESTATE_ISSUES: "부동산 이슈를 한눈에",
  WALL_ST_ISSUES: "월가 이슈를 한눈에",
} as const;

type HeaderTitleCode = keyof typeof HEADER_TITLE_TEXT;

const HEADER_LABEL_TEXT = {
  REAL_ESTATE_PICK: "부동산 픽",
  WALL_ST: "WALL ST",
} as const;
const FIXED_BRAND_NAME = "판교불패";
const FIXED_COMPASS_LOGO_DATA_URI = "data:image/png;base64,";

type HeaderLabelCode = keyof typeof HEADER_LABEL_TEXT;

const HEADER_LABEL_CODE_BY_TITLE: Record<HeaderTitleCode, HeaderLabelCode> = {
  REAL_ESTATE_ISSUES: "REAL_ESTATE_PICK",
  WALL_ST_ISSUES: "WALL_ST",
};
const DEFAULT_TOP_BAR_COLOR_HEX = "1A3C34";
const DEFAULT_BOTTOM_BAR_COLOR_HEX = "1A3C34";

const CATEGORY_TEXT: Record<string, string> = {
  US_MARKET: "미국증시",
  FUTURES: "선물시장",
  COMMODITIES: "원자재",
  FX: "환율",
  TECH: "테크",
  MACRO: "매크로",
  OTHER: "기타",
};

type CategoryCode = keyof typeof CATEGORY_TEXT;

const CATEGORY_CODE_MAP: Record<string, CategoryCode> = {
  US_MARKET: "US_MARKET",
  MARKETS: "US_MARKET",
  EQUITIES: "US_MARKET",
  "US MARKET": "US_MARKET",
  "US MARKETS": "US_MARKET",
  "미국증시": "US_MARKET",
  "미국 시장": "US_MARKET",
  "미증시": "US_MARKET",
  FUTURES: "FUTURES",
  "FIXED INCOME": "FUTURES",
  BOND: "FUTURES",
  "선물시장": "FUTURES",
  "채권": "FUTURES",
  "선물": "FUTURES",
  COMMODITIES: "COMMODITIES",
  "원자재": "COMMODITIES",
  "원자재시장": "COMMODITIES",
  FX: "FX",
  "FOREIGN EXCHANGE": "FX",
  "외환": "FX",
  "외환시장": "FX",
  TECH: "TECH",
  TECHNOLOGY: "TECH",
  EARNINGS: "TECH",
  "테크": "TECH",
  "기술주": "TECH",
  MACRO: "MACRO",
  "매크로": "MACRO",
  OTHER: "OTHER",
  CRYPTO: "OTHER",
  "기타": "OTHER",
};

function resolveCategoryCode(raw: string | null | undefined): CategoryCode | null {
  if (!raw) return null;
  const key = normalizeCategoryLookupKey(raw);
  return CATEGORY_CODE_MAP[key] || null;
}

function resolveHeaderTitleCode(raw: string | null | undefined): HeaderTitleCode {
  if (!raw) return "REAL_ESTATE_ISSUES";
  const code = raw.toUpperCase().trim();
  if (code === "REAL_ESTATE_ISSUES" || code === "WALL_ST_ISSUES") return code;
  const matched = Object.entries(HEADER_TITLE_TEXT).find(([, value]) => value === raw)?.[0];
  return matched === "WALL_ST_ISSUES" ? "WALL_ST_ISSUES" : "REAL_ESTATE_ISSUES";
}

function resolveHeaderLabelCode(_raw: string | null | undefined, titleCode: HeaderTitleCode): HeaderLabelCode {
  return HEADER_LABEL_CODE_BY_TITLE[titleCode];
}

function normalizeBarColorHex(raw: unknown, fallback: string): string {
  if (typeof raw !== "string") return fallback;
  const match = raw.trim().match(/^#?([0-9a-fA-F]{6})$/);
  return match ? match[1].toUpperCase() : fallback;
}

function formatSlideDate(raw: string | null | undefined): string {
  if (!raw) return "";
  const match = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return raw;
  const [, year, month, day] = match;
  return `${year.slice(-2)}.${Number(month)}.${day}`;
}

function getCurrentKstDateIso(now: Date = new Date()): string {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: "Asia/Seoul",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).formatToParts(now);
  const year = parts.find((part) => part.type === "year")?.value || "";
  const month = parts.find((part) => part.type === "month")?.value || "";
  const day = parts.find((part) => part.type === "day")?.value || "";
  return `${year}-${month}-${day}`;
}

function resolveCategoryText(raw: string | null | undefined): string {
  if (!raw) return CATEGORY_TEXT.OTHER;
  const code = resolveCategoryCode(raw);
  return code ? CATEGORY_TEXT[code] : raw.trim();
}

function resolveCategoryFilenameToken(raw: string | null | undefined): string {
  const code = resolveCategoryCode(raw);
  if (code) return code;
  return slug(raw || "other").replace(/-/g, "_").toUpperCase() || "OTHER";
}

function getHeadlineSize(value: string): number {
  const normalized = value.replace(/\s+/g, "");
  if (!normalized) return 132;
  if (normalized.length <= 14) return 132;
  if (normalized.length <= 22) return 116;
  if (normalized.length <= 30) return 102;
  if (normalized.length <= 38) return 90;
  return 78;
}

function getSummaryFontSize(lines: string[]): number {
  const longest = lines.reduce((max, line) => Math.max(max, line.replace(/\s+/g, "").length), 0);
  const lineCount = Math.max(lines.length, 1);
  if (lineCount >= 3) {
    if (longest <= 18) return 58;
    if (longest <= 24) return 54;
    return 50;
  }
  if (longest <= 18) return 63;
  if (longest <= 24) return 58;
  return 52;
}

function normalizeSummaryLines(value: unknown): [string, string, string] {
  if (!Array.isArray(value)) return ["", "", ""];
  const lines = value.slice(0, 3).map((line) => String(line || "").trim());
  while (lines.length < 3) lines.push("");
  return [lines[0], lines[1], lines[2]];
}

function normalizeSourceText(value: unknown): string {
  return String(value ?? "")
    .replace(/\s+/g, " ")
    .replace(/^source\s*:\s*/i, "")
    .trim();
}

async function fetchAsBase64(url: string): Promise<{ data: string; mime: string } | null> {
  try {
    const response = await fetch(url);
    if (!response.ok) return null;
    const mime = response.headers.get("content-type") || "image/png";
    const buf = new Uint8Array(await response.arrayBuffer());
    let bin = "";
    for (let i = 0; i < buf.length; i += 1) bin += String.fromCharCode(buf[i]);
    return { data: btoa(bin), mime };
  } catch {
    return null;
  }
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const { reportId } = await req.json();
    if (!reportId) {
      return new Response(JSON.stringify({ error: "reportId required" }), {
        status: 400,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const auth = req.headers.get("Authorization") || "";
    const supabase = createClient(
      Deno.env.get("SUPABASE_URL")!,
      Deno.env.get("SUPABASE_ANON_KEY")!,
      { global: { headers: { Authorization: auth } } },
    );

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) throw new Error("인증이 필요합니다.");

    const { data: report, error } = await supabase.from("reports").select("*").eq("id", reportId).maybeSingle();
    if (error || !report) throw new Error("리포트를 찾을 수 없습니다.");

    const titleCode = resolveHeaderTitleCode(report.header_title);
    const labelCode = resolveHeaderLabelCode(report.header_label, titleCode);
    const headerTitle = HEADER_TITLE_TEXT[titleCode];
    const headerLabel = HEADER_LABEL_TEXT[labelCode];
    const categoryText = resolveCategoryText(report.category);
    const summaryLines = normalizeSummaryLines(report.summary_lines).filter((line) => line.trim().length > 0);
    const summaryText = summaryLines.length > 0 ? summaryLines.join("\n") : "요약 문장";
    const summaryPt = pt(getSummaryFontSize(summaryLines));
    const sourceText = normalizeSourceText(report.source);
    const slideDateIso = getCurrentKstDateIso();
    const unifiedBarColorSource =
      typeof report.top_bar_color === "string" && report.top_bar_color.trim()
        ? report.top_bar_color
        : report.bottom_bar_color;
    const topBarColorHex = normalizeBarColorHex(unifiedBarColorSource, DEFAULT_TOP_BAR_COLOR_HEX);
    const bottomBarColorHex = topBarColorHex;

    const pptx = new PptxGenJS();
    pptx.defineLayout({ name: "C2I", width: SLIDE_W_IN, height: SLIDE_H_IN });
    pptx.layout = "C2I";

    const slide = pptx.addSlide();
    slide.background = { color: "FFFFFF" };

    slide.addShape("rect", {
      x: px(LAYOUT.headerBand.x),
      y: px(LAYOUT.headerBand.y),
      w: px(LAYOUT.headerBand.w),
      h: px(LAYOUT.headerBand.h),
      fill: { color: topBarColorHex },
      line: { color: topBarColorHex },
    });

    slide.addImage({
      data: FIXED_COMPASS_LOGO_DATA_URI,
      x: px(26),
      y: px(24),
      w: px(64),
      h: px(64),
    });

    slide.addText(FIXED_BRAND_NAME, {
      x: px(102),
      y: px(30),
      w: px(340),
      h: px(56),
      fontSize: pt(42),
      bold: true,
      color: "FFFFFF",
      fontFace: "Pretendard",
    });

    slide.addText(headerTitle, {
      x: px(360),
      y: px(24),
      w: px(720),
      h: px(70),
      fontSize: pt(70),
      bold: true,
      color: "FFFFFF",
      align: "center",
      fontFace: "Pretendard",
    });

    const labelX = SLIDE_W_IN - px(292);
    const labelY = px(20);
    const labelW = px(252);
    const labelH = px(78);
    slide.addShape("rect", {
      x: labelX,
      y: labelY,
      w: labelW,
      h: labelH,
      fill: { color: topBarColorHex },
      line: { color: "FFFFFF", pt: 2 },
    });

    if (labelCode === "WALL_ST") {
      slide.addText("WALL", {
        x: labelX + px(24),
        y: labelY + px(19),
        w: px(164),
        h: px(44),
        fontSize: pt(48),
        bold: true,
        color: "FFFFFF",
        fontFace: "Pretendard",
      });
      slide.addText("ST", {
        x: labelX + px(192),
        y: labelY + px(27),
        w: px(40),
        h: px(26),
        fontSize: pt(24),
        bold: true,
        color: "FFFFFF",
        fontFace: "Pretendard",
      });
    } else {
      slide.addText(headerLabel, {
        x: labelX,
        y: labelY + px(16),
        w: labelW,
        h: px(46),
        fontSize: pt(48),
        bold: true,
        color: "FFFFFF",
        align: "center",
        fontFace: "Pretendard",
      });
    }

    if (report.chart_image_url) {
      const image = await fetchAsBase64(report.chart_image_url);
      if (image) {
        slide.addImage({
          data: `data:${image.mime};base64,${image.data}`,
          x: px(LAYOUT.chartZone.x),
          y: px(LAYOUT.chartZone.y),
          w: px(LAYOUT.chartZone.w),
          h: px(LAYOUT.chartZone.h),
          sizing: { type: "contain", w: px(LAYOUT.chartZone.w), h: px(LAYOUT.chartZone.h) },
        });
      }
    }

    slide.addShape("rect", {
      x: px(LAYOUT.chartZone.x),
      y: px(LAYOUT.chartZone.y),
      w: px(LAYOUT.chartZone.w),
      h: px(LAYOUT.chartZone.h),
      fill: { type: "none" },
      line: { color: "E5E7EB", pt: 1 },
    });

    const categoryLength = categoryText.replace(/\s+/g, "").length;
    const categoryTagWidth = Math.max(px(240), Math.min(px(680), px(90 + categoryLength * 58)));
    slide.addShape("roundRect", {
      x: px(LAYOUT.categoryTag.x),
      y: px(LAYOUT.categoryTag.y),
      w: categoryTagWidth,
      h: px(LAYOUT.categoryTag.h),
      fill: { color: "C00000" },
      line: { color: "C00000" },
    });
    slide.addText(categoryText, {
      x: px(LAYOUT.categoryTag.x),
      y: px(LAYOUT.categoryTag.y + 17),
      w: categoryTagWidth,
      h: px(52),
      fontSize: pt(66),
      bold: true,
      color: "FFFFFF",
      align: "center",
      fontFace: "Pretendard",
    });

    const headline = report.headline || "헤드라인을 입력하세요";
    slide.addText(headline, {
      x: px(LAYOUT.headlineZone.x),
      y: px(LAYOUT.headlineZone.y),
      w: px(LAYOUT.headlineZone.w),
      h: px(LAYOUT.headlineZone.h),
      fontSize: pt(getHeadlineSize(headline)),
      bold: true,
      color: "111111",
      fontFace: "Pretendard",
      valign: "top",
      breakLine: true,
      margin: 0,
    });

    slide.addShape("roundRect", {
      x: px(LAYOUT.summaryBadge.x),
      y: px(LAYOUT.summaryBadge.y),
      w: px(LAYOUT.summaryBadge.w),
      h: px(LAYOUT.summaryBadge.h),
      fill: { color: "111111" },
      line: { color: "111111" },
    });
    slide.addText("\uD575\uC2EC\uC694\uC57D", {
      x: px(LAYOUT.summaryBadge.x),
      y: px(LAYOUT.summaryBadge.y + 8),
      w: px(LAYOUT.summaryBadge.w),
      h: px(LAYOUT.summaryBadge.h),
      fontSize: pt(40),
      bold: true,
      color: "FFFFFF",
      align: "center",
      valign: "mid",
      breakLine: false,
      fontFace: "Malgun Gothic",
    });

    slide.addText(summaryText, {
      x: px(LAYOUT.summaryTextZone.x),
      y: px(LAYOUT.summaryTextZone.y),
      w: px(LAYOUT.summaryTextZone.w),
      h: px(LAYOUT.summaryTextZone.h),
      fontSize: summaryPt,
      bold: true,
      color: "111111",
      fontFace: "Pretendard",
      margin: 0,
      breakLine: true,
      valign: "top",
      fit: "shrink",
    });

    if (sourceText) {
      slide.addText(`SOURCE: ${sourceText}`, {
        x: px(LAYOUT.chartZone.x),
        y: px(LAYOUT.chartZone.y + LAYOUT.chartZone.h + 8),
        w: px(LAYOUT.chartZone.w),
        h: px(28),
        fontSize: pt(26),
        bold: true,
        color: "111111",
        align: "right",
        fontFace: "Pretendard",
        margin: 0,
      });
    }

    slide.addShape("rect", {
      x: px(LAYOUT.footerBand.x),
      y: px(LAYOUT.footerBand.y),
      w: px(LAYOUT.footerBand.w),
      h: px(LAYOUT.footerBand.h),
      fill: { color: bottomBarColorHex },
      line: { color: bottomBarColorHex },
    });

    slide.addText("Premium\nContents.", {
      x: px(34),
      y: px(LAYOUT.footerBand.y + 12),
      w: px(176),
      h: px(92),
      fontSize: pt(38),
      italic: true,
      color: "D7EADF",
      fontFace: "Times New Roman",
      breakLine: true,
      margin: 0,
    });

    slide.addText("네이버프리미엄 콘텐츠 제공", {
      x: px(206),
      y: px(LAYOUT.footerBand.y + 38),
      w: px(770),
      h: px(46),
      fontSize: pt(42),
      bold: true,
      color: "FFFFFF",
      fontFace: "Pretendard",
    });


    slide.addText(formatSlideDate(slideDateIso), {
      x: SLIDE_W_IN - px(286),
      y: px(LAYOUT.footerBand.y + 34),
      w: px(248),
      h: px(54),
      fontSize: pt(54),
      color: "FFFFFF",
      align: "right",
      fontFace: "JetBrains Mono",
      bold: true,
    });

    const out = await pptx.write({ outputType: "uint8array" }) as Uint8Array;

    const dateStr = slideDateIso.replace(/-/g, "");
    const categoryToken = resolveCategoryFilenameToken(report.category);
    const headlineToken = toStorageKeySegment(report.headline || "", `report-${reportId.slice(0, 8)}`);
    const filename = `C2I_${categoryToken}_${dateStr}_${headlineToken}.pptx`;
    const path = `${user.id}/${reportId}/${filename}`;

    const { error: uploadError } = await supabase.storage.from("exports").upload(path, out, {
      contentType: "application/vnd.openxmlformats-officedocument.presentationml.presentation",
      upsert: true,
    });
    if (uploadError) throw uploadError;

    const { data: signed } = await supabase.storage.from("exports").createSignedUrl(path, 60 * 60 * 24 * 7);
    const fileUrl = signed?.signedUrl;

    await supabase.from("export_jobs").insert({
      report_id: reportId,
      user_id: user.id,
      status: "completed",
      file_url: fileUrl,
    });
    await supabase.from("reports").update({ status: "completed", export_status: "ready", slide_date: slideDateIso }).eq("id", reportId);

    return new Response(JSON.stringify({ fileUrl, filename }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (error) {
    console.error(error);
    return new Response(JSON.stringify({ error: error instanceof Error ? error.message : "unknown" }), {
      status: 500,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});
